import { redirect } from "next/navigation";
import {
  Clock3,
  FileText,
  Folder,
  Home,
  LogIn,
  LogOut,
  Settings,
  User,
} from "lucide-react";

import { Main } from "@/components/Main";
import { Button } from "@/components/ui/button";
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import { auth0 } from "@/lib/auth0";

export default async function AppPage() {
  const session = await auth0.getSession();

  if (!session?.user) {
    redirect("/");
  }

  return (
    <div className="min-h-screen bg-slate-50 text-slate-900">
      <div className="grid min-h-screen lg:grid-cols-[260px_1fr]">
        <aside className="bg-gradient-to-b from-blue-600 to-indigo-700 text-white px-6 py-8 flex flex-col gap-8">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-white/10 rounded-lg flex items-center justify-center">
              <Home className="h-5 w-5" />
            </div>
            <div>
              <p className="text-sm text-blue-100">DocGen</p>
              <p className="text-lg font-semibold">Workspace</p>
            </div>
          </div>

          <nav className="space-y-1">
            {[
              { label: "Saved templates", icon: FileText },
              { label: "Org templates", icon: Folder },
              { label: "Past jobs", icon: Clock3 },
              { label: "Account", icon: User },
              { label: "Settings", icon: Settings },
            ].map(({ label, icon: Icon }) => (
              <Button
                key={label}
                variant="ghost"
                className="w-full justify-start gap-3 text-white/90 hover:bg-white/10 hover:text-white"
                asChild
              >
                <a href="#">
                  <Icon className="h-4 w-4" />
                  {label}
                </a>
              </Button>
            ))}
          </nav>

          <div className="mt-auto space-y-2">
            <Button
              variant="outline"
              className="w-full justify-start gap-3 border-white/30 text-white hover:bg-white/10 hover:text-white"
              asChild
            >
              <a href="/auth/login">
                <LogIn className="h-4 w-4" />
                Log in
              </a>
            </Button>
            <Button
              className="w-full justify-start gap-3 bg-white text-slate-900 hover:bg-white/90"
              asChild
            >
              <a href="/auth/logout">
                <LogOut className="h-4 w-4" />
                Log out
              </a>
            </Button>
          </div>
        </aside>

        <main className="p-6 lg:p-10 space-y-6">
          <div className="flex items-center justify-between gap-4">
            <div>
              <p className="text-sm text-slate-600">Document builder</p>
              <h1 className="text-2xl font-semibold text-slate-900">
                Generate documents
              </h1>
            </div>
            {session.user?.email && (
              <Card className="hidden sm:block">
                <CardHeader className="py-3">
                  <CardTitle className="text-sm font-medium">
                    {session.user.email}
                  </CardTitle>
                  <CardDescription>Signed in</CardDescription>
                </CardHeader>
              </Card>
            )}
          </div>

          <Card className="border-slate-200 shadow-sm">
            <CardContent className="pt-6">
              <Main />
            </CardContent>
          </Card>
        </main>
      </div>
    </div>
  );
}
